import decimal

def calculate_compound_interest(principal, rate, time, n):
    decimal.getcontext().prec = 28
    return decimal.Decimal(principal) * (1 + decimal.Decimal(rate) / decimal.Decimal(n)) ** (decimal.Decimal(n) * decimal.Decimal(time))
